<?php
namespace App\Http\Controllers\Api;
use App\Domain\Repayments\Actions\RecordLoanRepayment;use App\Domain\Repayments\Actions\ReverseLoanRepayment;use App\Http\Controllers\Controller;use App\Models\Loan;use App\Models\LoanRepayment;use Illuminate\Http\JsonResponse;use Illuminate\Http\Request;
class LoanRepaymentController extends Controller{public function index(Loan $loan):JsonResponse{return response()->json($loan->repayments()->with('allocations')->latest('received_at')->paginate());}public function store(Request $request,Loan $loan,RecordLoanRepayment $action):JsonResponse{$d=$request->validate(['idempotency_key'=>['required','string','max:120'],'channel'=>['required','in:cash,bank_transfer,card,direct_debit,mobile_money,ussd,cheque,employer_deduction,other'],'currency'=>['sometimes','string','size:3'],'amount_minor'=>['required','integer','min:1'],'external_reference'=>['nullable','string','max:160'],'received_at'=>['nullable','date'],'notes'=>['nullable','string','max:2000']]);return response()->json($action->execute($loan,$d),201);}public function reverse(Request $request,LoanRepayment $repayment,ReverseLoanRepayment $action):JsonResponse{$d=$request->validate(['reason'=>['required','string','max:2000']]);return response()->json($action->execute($repayment,$d['reason']),201);}}
